using System; using System.IO; using Microsoft.Extensions.Logging; namespace FlowReveal.Services.Parser { public static class HttpDebugLogger { private static readonly object _lock = new(); private static int _requestCount = 0; private static int _responseCount = 0; public static void LogHttpRequest(byte[] data, int offset, int length, ILogger logger) { lock (_lock) { _requestCount++; var fileName = $"http_request_{_requestCount}_{DateTime.Now:yyyyMMdd_HHmmss_fff}.bin"; File.WriteAllBytes(fileName, data[offset..(offset + length)]); logger.LogInformation("Saved HTTP request {Count} to {File}", _requestCount, fileName); } } public static void LogHttpResponse(byte[] data, int offset, int length, ILogger logger) { lock (_lock) { _responseCount++; var fileName = $"http_response_{_responseCount}_{DateTime.Now:yyyyMMdd_HHmmss_fff}.bin"; File.WriteAllBytes(fileName, data[offset..(offset + length)]); logger.LogInformation("Saved HTTP response {Count} to {File}", _responseCount, fileName); } } } }